def normalizar_nivel(nivel):
    """
    Normaliza los niveles para la búsqueda en PARRAFOS_CIERRE.
    - 'muy bajo' se trata como 'bajo'
    - 'muy alto' se trata como 'alto'
    - otros niveles se mantienen igual
    
    Args:
        nivel: str - nivel original ('muy bajo', 'bajo', 'normal', 'alto', 'muy alto')
        
    Returns:
        str - nivel normalizado
    """
    if nivel == 'muy bajo':
        return 'bajo'
    elif nivel == 'muy alto':
        return 'alto'
    else:
        return nivel


def obtener_parrafo_cierre(TR, O, C, CON, VAR, VAR_especial, nombre):
    """
    Obtiene el párrafo de cierre según las clasificaciones.
    Implementa normalización de niveles y reemplazo dinámico del placeholder VAR.
    
    Args:
        TR: Clasificación de velocidad de procesamiento
        O: Clasificación de errores de omisión
        C: Clasificación de errores de comisión
        CON: Clasificación de concentración
        VAR: Clasificación de variabilidad
        VAR_especial: bool - Si se cumple condición especial de VAR
        nombre: Nombre del evaluado
        
    Returns:
        str - Párrafo de cierre completo con VAR insertado
    """
    # Normalizar niveles para búsqueda
    TR_norm = normalizar_nivel(TR)
    O_norm = normalizar_nivel(O)
    C_norm = normalizar_nivel(C)
    CON_norm = normalizar_nivel(CON)
    
    # Crear la clave para buscar en PARRAFOS_CIERRE
    clave = (TR_norm, O_norm, C_norm, CON_norm)
    
    # Buscar el párrafo correspondiente
    parrafo = PARRAFOS_CIERRE.get(clave, None)
    
    if parrafo is None:
        # Si no existe esa combinación exacta, usar un párrafo genérico
        parrafo = f'''Ante una tarea de discriminación visual bajo presión temporal, {{nombre}} mostró un perfil caracterizado por velocidad de procesamiento {TR}, nivel de omisiones {O}, precisión {C} y concentración {CON}.'''
    
    # Obtener el párrafo VAR correspondiente
    var_key = VAR
    # Determinar si usar la versión especial
    if VAR_especial and (VAR == 'alto' or VAR == 'muy alto'):
        var_key = VAR + '_especial'
    
    # Obtener párrafo VAR
    parrafo_var_texto = PARRAFOS_VAR.get(var_key, PARRAFOS_VAR.get(VAR, ''))
    parrafo_var_texto = parrafo_var_texto.format(nombre=nombre)
    
    # Obtener párrafo VAR cierre
    if VAR in ['alto', 'muy alto']:
        parrafo_var_cierre = PARRAFOS_VAR_CIERRE.get((VAR, VAR_especial), '')
    else:
        parrafo_var_cierre = PARRAFOS_VAR_CIERRE.get(VAR, '')
    parrafo_var_cierre = parrafo_var_cierre.format(nombre=nombre)
    
    # Reemplazar el placeholder "((Añadir párrafo VAR))" con el párrafo VAR_CIERRE
    # y continuar el resto del texto en un nuevo párrafo
    if '((Añadir párrafo VAR))' in parrafo:
        # Dividir el texto en dos partes: antes y después del placeholder
        partes = parrafo.split('((Añadir párrafo VAR))')
        if len(partes) == 2:
            parte_antes = partes[0].strip()
            parte_despues = partes[1].strip()
            
            # Reconstruir con el párrafo VAR_CIERRE en medio
            parrafo = f"{parte_antes} {parrafo_var_cierre}\n\n{parte_despues}"
        else:
            # Si algo salió mal, simplemente reemplazar directamente
            parrafo = parrafo.replace('((Añadir párrafo VAR))', parrafo_var_cierre)
    
    # Formatear con el nombre
    parrafo = parrafo.format(nombre=nombre)
    
    return parrafo